ider özel alanı"></label><?php endif; ?><label>Durum<select name="status"><option value="active">Aktif</option><option value="inactive">Pasif</option></select></label><label>Test Modu<select name="test_mode"><option value="1">Açık</option><option value="0">Kapalı</option></select></label></div><button class="ao-btn">Kaydet</button></form></div><div class="rc7-card"><h3>Kayıtlı <?= e($p['title']) ?></h3><table class="rc7-table"><thead><tr><th>Ad</th><th>Provider</th><th>Durum</th><th>İşlem</th></tr></thead><tbody><?php foreach($apis as $a): if(!array_key_exists($a['provider'],$p['items'])) continue; ?><tr><td><?= e($a['name']) ?><br><small><?= e($a['endpoint']) ?></small></td><td><?= e($p['items'][$a['provider']] ?? $a['provider']) ?></td><td><span class="rc7-pill <?= ($a['status']??'')==='active'?'green':'orange' ?>"><?= e($a['status']) ?></span></td><td><a class="ao-mini-btn" href="<?= url('admin/api-integrations/test?id='.(int)$a['id']) ?>">Test Et</a></td></tr><?php endforeach; ?></tbody></table></div></div></section><?php endforeach; ?>
